#include<bits/stdc++.h>
using namespace std;
const int N=25;
int n,a[N][N],dp[(1<<20)+5][25];
int main()
{
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++) cin>>a[i][j];
	}
	memset(dp,0x3f,sizeof(dp));
	dp[1][1]=0;
	for(int i=1;i<(1<<n);i++)
	{
		for(int j=1;j<=n;j++)
		{
			if((i&(1<<(j-1)))==0) continue;
			for(int k=1;k<=n;k++)
			{
				if(i&(1<<(k-1))) continue;
				dp[i+(1<<(k-1))][k]=min(dp[i][j]+a[j][k],dp[i+(1<<(k-1))][k]);
			}
		}
	}
	cout<<dp[(1<<n)-1][n];
	return 0;
}
